def max_independent_set(root):
    """
    Returns the size of the maximum independent set.
    dp(node) -> (include, exclude)
      include = size of MIS in subtree when node IS selected
      exclude = size of MIS in subtree when node is NOT selected
    """
    def dp(node):
        if not node:
            return (0, 0)
        li, le = dp(node.left)
        ri, re = dp(node.right)
        # If we include this node, children must be excluded
        include = 1 + ___________
        # If we exclude this node, children can be included or excluded (take best)
        exclude  = ___________
        return (include, exclude)

    inc, exc = dp(root)
    return max(inc, exc)
